import React, { useEffect, useState, useCallback, useMemo } from 'react';
import { useTable, useSortBy, useGlobalFilter, usePagination } from 'react-table';
import EditPurchase from './EditPurchase';
import './PurchaseFunc.css';
import AddPurchase from './AddPurchase';

const PurchaseTable = ({ columns, data, handleEdit, handleDelete, editingPurchase, vendors, locations, materials }) => {
  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    page,
    prepareRow,
    state: { pageIndex, pageSize, globalFilter },
    gotoPage,
    nextPage,
    previousPage,
    canNextPage,
    canPreviousPage,
    setPageSize,
    setGlobalFilter,
  } = useTable(
    {
      columns,
      data,
      initialState: {
        pageIndex: 0,
        pageSize: 10,
        sortBy: [
          {
            id: 'id',
            desc: true,
          },
        ],
      },
    },
    useGlobalFilter,
    useSortBy,
    usePagination
  );

  return (
    <div>
      <div className="search">
        <input
          type="text"
          value={globalFilter || ''}
          onChange={(e) => setGlobalFilter(e.target.value)}
          placeholder="Search..."
        />
      </div>
      <table {...getTableProps()} className="purchase-table">
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                  {column.render('Header')}
                  <span>{column.isSorted ? (column.isSortedDesc ? ' 🔽' : ' 🔼') : ''}</span>
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {page.map((row) => {
            prepareRow(row);
            return (
              <React.Fragment key={row.id}>
                <tr {...row.getRowProps()}>
                  {row.cells.map((cell) => (
                    <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                  ))}
                </tr>
                {editingPurchase && editingPurchase.id === row.original.id && (
                  <tr key={`edit-${row.original.id}`}>
                    <td colSpan={columns.length}>
                      <EditPurchase
                        purchase={editingPurchase}
                        handleUpdate={handleEdit}
                        vendors={vendors}
                        locations={locations}
                        materials={materials}
                      />
                    </td>
                  </tr>
                )}
              </React.Fragment>
            );
          })}
        </tbody>
      </table>
      <div>
        <button onClick={() => previousPage()} disabled={!canPreviousPage}>
          Previous
        </button>
        <button onClick={() => nextPage()} disabled={!canNextPage}>
          Next
        </button>
        <span>
          Page{' '}
          <strong>
            {pageIndex + 1} of {Math.ceil(data.length / pageSize)}
          </strong>{' '}
        </span>
        <span>
          | Go to page:{' '}
          <input
            type="number"
            defaultValue={pageIndex + 1}
            onChange={(e) => {
              const page = e.target.value ? Number(e.target.value) - 1 : 0;
              gotoPage(page);
            }}
            style={{ width: '50px' }}
          />
        </span>
        <select
          value={pageSize}
          onChange={(e) => {
            setPageSize(Number(e.target.value));
          }}
        >
          {[10, 25, 50].map((pageSize) => (
            <option key={pageSize} value={pageSize}>
              Show {pageSize}
            </option>
          ))}
        </select>
      </div>
    </div>
  );
};

const PurchaseFunc = ({ materials, purchases, locations, vendors, setPurchases }) => {
  const [editingPurchase, setEditingPurchase] = useState(null);
  const [transformedPurchases, setTransformedPurchases] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);
  
  const fetchTransformedPurchases = useCallback((purchases, locations, materials, vendors) => {
    setIsLoading(true);
    setError(null);
  
    const transformedPurchases = purchases.map((purchase) => {
      const location = locations.find((loc) => loc.id === purchase.location);
      const material = materials.find((mat) => mat.matid === purchase.materialid);
      const vendor = vendors.find((ven) => ven.vendorid === purchase.vendor);
      return {
        ...purchase,
        location: location ? location.locationname : 'Unknown Location',
        name: material ? material.name : 'Unknown Material',
        vendor: vendor ? vendor.name : 'Unknown Vendor',
      };
    });
  
    setTransformedPurchases(transformedPurchases);
    setIsLoading(false);
  }, []);

  

  const handleAdd = useCallback((newPurchase) => {
    fetch('http://localhost:8081/PurchasesAPI', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(newPurchase),
    })
      .then((response) => {
        if (response.ok) {
          return response.json();
        } else {
          throw new Error('Error adding purchase');
        }
      })
      .then((data) => {
        setPurchases((prevPurchases) => [...prevPurchases, data]);
        setEditingPurchase(null);
      })
      .catch((error) => {
        console.log('Error adding purchase:', error);
      });
  }, [setPurchases, setEditingPurchase]);

  const handleEdit = useCallback((purchase) => {
    if (editingPurchase && editingPurchase.id === purchase.id) {
      alert('Purchase is already being edited.');
      return;
    }

    setEditingPurchase(purchase);
  }, [editingPurchase]);

  const handleDelete = useCallback((deletedPurchase) => {
    const isConfirmed = window.confirm('Are you sure you want to delete this purchase?');

    if (isConfirmed) {
      fetch(`http://localhost:8081/PurchasesAPI/${deletedPurchase.id}`, {
        method: 'DELETE',
      })
        .then(() => {
          const updatedPurchaseList = purchases.filter((p) => p.id !== deletedPurchase.id);
          setPurchases(updatedPurchaseList);
        })
        .catch((error) => {
          console.log('Error deleting purchase:', error);
        });
    }
  }, [purchases, setPurchases]);

  const columns = useMemo(
    () => [
      { Header: 'ID', accessor: 'id' },
      { Header: 'Location', accessor: 'location' },
      { Header: 'Material ID', accessor: 'materialid' },
      { Header: 'Material Name', accessor: 'name' },
      { Header: 'Width', accessor: 'width' },
      { Header: 'Lot No', accessor: 'lotnumber' },
      { Header: 'Quantity', accessor: 'quantity' },
      { Header: 'Price', accessor: 'price' },
      {
        Header: 'Vendor',
        accessor: 'vendor',
        Cell: ({ value }) => {
          return (
            <a href={`http://localhost:8081/vendors/${value}`} target="_blank" rel="noopener noreferrer">
              {value}
            </a>
          );
        },
      },
      { Header: 'Date', accessor: 'date' },
      {
        Header: 'Actions',
        accessor: 'actions',
        Cell: ({ row }) => (
          <div>
            <button onClick={() => handleEdit(row.original)}>Edit</button>
            <button onClick={() => handleDelete(row.original)}>Delete</button>
          </div>
        ),
      },
    ],
    [handleEdit, handleDelete]
  );

  return (
    <div>
      {isLoading ? (
        <div>Loading...</div>
      ) : error ? (
        <div>Error: {error.message}</div>
      ) : (
        <>
          <AddPurchase
            handleAdd={handleAdd}
            locations={locations}
            vendors={vendors}
            materials={materials}
            setPurchases={setPurchases}
          />
          <PurchaseTable
            columns={columns}
            data={transformedPurchases}
            handleEdit={handleEdit}
            handleDelete={handleDelete}
            editingPurchase={editingPurchase}
            vendors={vendors}
            locations={locations}
            materials={materials}
          />
        </>
      )}
    </div>
  );
};

export default PurchaseFunc;
